            continue
        to_addr = (e.get("to_addr") or "").lower()
        cc_addr = (e.get("cc_addr") or "").lower()
        all_recipients = to_addr + " " + cc_addr

        if "teresa.vang@ridgelinegear.com" in all_recipients:
            sent_to_teresa.append(e)
        if "marcus.evans@ridgelinegear.com" in all_recipients:
            sent_to_marcus.append(e)

    issues = []
