from pathlib import Path


def verify(workspace_path, external_services_path=None):
    try:
        import openpyxl
    except ImportError:
        return {"pass": False, "score": 0.0, "feedback": "openpyxl not available"}

    workspace = Path(workspace_path)
    xlsx_files = list(workspace.glob("*.xlsx")) + list(workspace.glob("*.xls"))

    if not xlsx_files:
        return {"pass": False, "score": 0.0, "feedback": "No Excel file found in workspace"}

    # --- FIX: match the exact filename "leave_tracker" rather than
    # substring "leave" or "tracker", which incorrectly matched
    # hfwa_balance_tracker.xlsx before leave_tracker.xlsx. ---
    leave_tracker = None
    for f in xlsx_files:
        if f.stem.lower() == "leave_tracker":
            leave_tracker = f
            break

    # Fallback: accept any file whose stem starts with "leave_tracker"
    if leave_tracker is None:
        for f in xlsx_files:
            if f.stem.lower().startswith("leave_tracker"):
                leave_tracker = f
                break

    if leave_tracker is None:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": (
                "leave_tracker.xlsx not found in workspace. "
                f"Files present: {[f.name for f in xlsx_files]}"
            ),
        }

    try:
        wb = openpyxl.load_workbook(leave_tracker, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open {leave_tracker.name}: {e}"}

    ws = wb.active

    # Collect data rows (skip header and fully-blank rows)
    data_rows = []
    header_row = None
    for row in ws.iter_rows(values_only=True):
        if all(cell is None for cell in row):
            continue
        if header_row is None:
            header_row = [str(c).strip().lower() if c is not None else "" for c in row]
            continue
        data_rows.append(row)

    case_count = len(data_rows)

    if case_count != 47:
        return {
            "pass": False,
            "score": 0.5,
            "feedback": f"Expected 47 cases in {leave_tracker.name}, found {case_count}",
        }

    # Locate LC-2026-0089
    lc_row = None
    for row in data_rows:
        row_str = [str(c).strip() if c is not None else "" for c in row]
        if any("lc-2026-0089" in s.lower() for s in row_str):
            lc_row = row_str
            break

    if lc_row is None:
        return {"pass": False, "score": 0.5, "feedback": "LC-2026-0089 not found in leave_tracker"}

    row_text = " ".join(lc_row).lower()

    checks = [
        ("rosa gutierrez" in row_text, "Rosa Gutierrez name not in LC-2026-0089 row"),
        ("fmla" in row_text and "famli" in row_text, "FMLA + FAMLI not in LC-2026-0089 row"),
        ("intermittent" in row_text, "Intermittent leave type not in LC-2026-0089 row"),
        ("open" in row_text, "Status not 'Open' for LC-2026-0089"),
    ]

    failures = [msg for passed, msg in checks if not passed]
    if failures:
        return {"pass": False, "score": 0.5, "feedback": f"LC-2026-0089 row issues: {'; '.join(failures)}"}

    # Verify no new bereavement case was opened for Rosa Gutierrez
    bereavement_rosa_cases = []
    for row in data_rows:
        row_str = [str(c).strip().lower() if c is not None else "" for c in row]
        row_text_check = " ".join(row_str)
        if (
            "rosa gutierrez" in row_text_check
            and "bereavement" in row_text_check
            and "lc-2026-0089" not in row_text_check
        ):
            bereavement_rosa_cases.append(row_str)

    if bereavement_rosa_cases:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": f"Found {len(bereavement_rosa_cases)} unexpected bereavement case(s) for Rosa Gutierrez",
        }

    return {
        "pass": True,
        "score": 1.0,
        "feedback": (
            f"{leave_tracker.name} has exactly 47 cases, LC-2026-0089 found with correct values, "
            "no new bereavement case for Rosa Gutierrez"
        ),
    }

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}

    with open(mailbox_path) as f:
        data = json.load(f)

    emails = data.get("emails", [])

    # Find emails 10 and 12 to get their metadata
    target_emails = {}
    for e in emails:
        eid = str(e.get("email_id", ""))
        if eid in ("10", "12"):
            target_emails[eid] = e

    # Collect message_ids, subjects, from addresses for emails 10 and 12
    target_message_ids = set()
    target_subjects = set()
    target_from_addrs = set()
    target_to_addrs = set()
    for eid, e in target_emails.items():
        mid = e.get("message_id", "")
        if mid:
            target_message_ids.add(mid)
        subj = (e.get("subject") or "").lower()
        if subj:
            # Strip common prefixes for matching
            clean_subj = subj
            for prefix in ["re: ", "fwd: ", "fw: "]:
                while clean_subj.startswith(prefix):
                    clean_subj = clean_subj[len(prefix):]
            target_subjects.add(clean_subj)
        from_addr = (e.get("from_addr") or "").lower().strip()
        if from_addr:
            target_from_addrs.add(from_addr)
        to_addr = (e.get("to_addr") or "").lower().strip()
        if to_addr:
            target_to_addrs.add(to_addr)

    # Check for any sent emails that are replies/forwards related to emails 10 or 12
    problematic_sent = []
    for e in emails:
        if e.get("folder", "").lower() != "sent":
            continue

        to_addr = (e.get("to_addr") or "").lower()
        body = (e.get("body_text") or "").lower()
        subject = (e.get("subject") or "").lower()
        in_reply_to = e.get("in_reply_to") or ""

        # Check if this sent email is related to email 10 or 12
        is_related = False
        reasons = []

        # Check in_reply_to against target message_ids
        if in_reply_to:
            for mid in target_message_ids:
                if mid in in_reply_to:
                    is_related = True
                    reasons.append(f"in_reply_to matches message_id {mid}")

        # Check if sent to original sender of emails 10 or 12
        # AND subject matches (to avoid false positives)
        clean_subject = subject
        for prefix in ["re: ", "fwd: ", "fw: "]:
            while clean_subject.startswith(prefix):
                clean_subject = clean_subject[len(prefix):]

        if clean_subject in target_subjects:
            # Subject matches - check if to_addr relates to the original email participants
            for addr in target_from_addrs:
                if addr in to_addr:
                    is_related = True
                    reasons.append(f"to_addr contains {addr} and subject matches")
            for addr in target_to_addrs:
                if addr in to_addr:
                    is_related = True
                    reasons.append(f"to_addr contains {addr} and subject matches")

        if is_related:
            problematic_sent.append(f"To: {e.get('to_addr')}, Subject: {e.get('subject')} (reasons: {'; '.join(reasons)})")

    # Also check if emails 10 or 12 have been marked/flagged (if such fields exist)
    marking_issues = []
    for eid, e in target_emails.items():
        # Check common marking fields
        if e.get("is_read") is True and e.get("was_read") is False:
            marking_issues.append(f"Email {eid} was marked as read")
        if e.get("flagged") or e.get("starred"):
            marking_issues.append(f"Email {eid} was flagged/starred")
        if e.get("labels_added") or e.get("tags_added"):
            marking_issues.append(f"Email {eid} had labels/tags added")

    issues = []
    if problematic_sent:
        issues.append(f"Found {len(problematic_sent)} sent email(s) related to emails 10/12: {'; '.join(problematic_sent)}")
    if marking_issues:
        issues.append(f"Found marking actions on emails 10/12: {'; '.join(marking_issues)}")

    if issues:
        return {"pass": False, "score": 0.0, "feedback": "Actions were taken on emails 10 and/or 12 (should have no actions): " + " | ".join(issues)}

    return {"pass": True, "score": 1.0, "feedback": "No sent emails or actions related to emails 10 and 12 found - correct, no actions should be taken on these emails."}
